import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function ClientManagement() {
  const [clients, setClients] = useState([]);
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    address: "",
    project: "",
    floor: "",
    room_number: "",
    amount_paid: ""
  });

  // ================= FETCH CLIENTS =================
  const fetchClients = async () => {
    try {
      const res = await fetch("http://localhost:5000/clients");
      const data = await res.json();
      setClients(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log("Client fetch error:", err);
      setClients([]);
    }
  };

  // ================= FETCH PROJECTS =================
  const fetchProjects = async () => {
    try {
      const res = await fetch("http://localhost:5000/projects");
      const data = await res.json();
      setProjects(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log("Project fetch error:", err);
      setProjects([]);
    }
  };

  useEffect(() => {
    fetchClients();
    fetchProjects();
  }, []);

  // ================= HANDLE INPUT =================
  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === "phone") {
      const numeric = value.replace(/\D/g, "");
      if (numeric.length <= 10) {
        setFormData({ ...formData, phone: numeric });
      }
      return;
    }

    setFormData({ ...formData, [name]: value });
  };

  // ================= GENERATE ROOMS =================
  const generateRooms = (floor) => {
    if (!floor) return [];

    let rooms = [];

    for (let i = 1; i <= 10; i++) {
      rooms.push(`${floor}${i.toString().padStart(2, "0")}`);
    }

    const bookedRooms = clients
      .filter(
        (c) =>
          String(c.floor) === String(floor) &&
          c.project === formData.project
      )
      .map((c) => String(c.room_number));

    return rooms.map((r) =>
      bookedRooms.includes(r) ? `${r} (Booked)` : r
    );
  };

  // ================= SUBMIT =================
  const handleSubmit = async () => {
    if (!formData.name) return alert("Enter name");
    if (formData.phone.length !== 10) return alert("Phone must be 10 digits");
    if (!formData.project) return alert("Select project");
    if (!formData.floor) return alert("Select floor");
    if (!formData.room_number) return alert("Select room");

    try {
      const res = await fetch(
        editId
          ? `http://localhost:5000/clients/${editId}`
          : "http://localhost:5000/clients",
        {
          method: editId ? "PUT" : "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            ...formData,
            room_number: formData.room_number.replace(" (Booked)", "")
          })
        }
      );

      const data = await res.json();

      if (!res.ok) {
        alert(data.error || "Save failed");
        return;
      }

      fetchClients();
      setShowForm(false);
      setEditId(null);

      setFormData({
        name: "",
        phone: "",
        address: "",
        project: "",
        floor: "",
        room_number: "",
        amount_paid: ""
      });

    } catch (err) {
      console.log(err);
      alert("Server error");
    }
  };

  // ================= EDIT =================
  const handleEdit = (client) => {
    setFormData({
      name: client.name,
      phone: client.phone,
      address: client.address,
      project: client.project,
      floor: client.floor,
      room_number: client.room_number,
      amount_paid: client.amount_paid
    });

    setEditId(client.id);
    setShowForm(true);
  };

  // ================= DELETE =================
  const handleDelete = async (id) => {
    try {
      await fetch(`http://localhost:5000/clients/${id}`, {
        method: "DELETE"
      });
      fetchClients();
    } catch (err) {
      console.log(err);
    }
  };

  // ================= SEARCH =================
  const filteredClients = clients.filter(
    (c) =>
      c.name?.toLowerCase().includes(search.toLowerCase()) ||
      c.project?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="client-dashboard">
      <Sidebar />

      <div className="client-main">
        <Topbar />

        <div className="client-content">

          <div className="client-header">
            <h1>Client & Booking Management</h1>
            <button className="btn-add" onClick={() => setShowForm(true)}>
              + Add Client
            </button>
          </div>

          <input
            type="text"
            placeholder="Search by name or project..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="search-input"
          />

          {showForm && (
            <div className="client-form">

              <div className="form-grid">

                <input name="name" value={formData.name} onChange={handleChange} placeholder="Name" />

                <input name="phone" value={formData.phone} onChange={handleChange} placeholder="Phone" />

                <input name="address" value={formData.address} onChange={handleChange} placeholder="Address" />

                <select name="project" value={formData.project} onChange={handleChange}>
                  <option value="">Select Project</option>
                  {projects.map((p) => (
                    <option key={p.id} value={p.projectName}>
                      {p.projectName}
                    </option>
                  ))}
                </select>

                <input name="floor" value={formData.floor} onChange={handleChange} placeholder="Floor" />

                <select name="room_number" value={formData.room_number} onChange={handleChange}>
                  <option value="">Select Room</option>
                  {generateRooms(formData.floor).map((r) => (
                    <option key={r} value={r}>
                      {r}
                    </option>
                  ))}
                </select>

                <input
                  name="amount_paid"
                  type="number"
                  value={formData.amount_paid}
                  onChange={handleChange}
                  placeholder="Amount Paid"
                />

              </div>

              <div className="form-actions">
                <button className="btn-save" onClick={handleSubmit}>
                  {editId ? "Update" : "Save"}
                </button>

                <button className="btn-cancel" onClick={() => setShowForm(false)}>
                  Cancel
                </button>
              </div>

            </div>
          )}

          <div className="client-table">

            <table>
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Phone</th>
                  <th>Project</th>
                  <th>Floor</th>
                  <th>Room</th>
                  <th>Paid</th>
                  <th>Actions</th>
                </tr>
              </thead>

              <tbody>
                {filteredClients.map((c) => (
                  <tr key={c.id}>
                    <td>{c.name}</td>
                    <td>{c.phone}</td>
                    <td>{c.project}</td>
                    <td>{c.floor}</td>
                    <td>{c.room_number}</td>
                    <td>₹{c.amount_paid}</td>

                    <td>
                      <button className="btn-edit" onClick={() => handleEdit(c)}>
                        Edit
                      </button>

                      <button className="btn-delete" onClick={() => handleDelete(c.id)}>
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}

                {filteredClients.length === 0 && (
                  <tr>
                    <td colSpan="7">No clients found</td>
                  </tr>
                )}

              </tbody>
            </table>

          </div>

        </div>
      </div>
    </div>
  );
}
